mapper.select:
SELECT a.id, a.title, a.slug, a.summary, a.cover_image, a.category_id, ac.name AS category_name, a.view_count, a.like_count, a.comment_count, a.word_count, a.reading_time, a.status, a.is_top, a.publish_time, a.create_time, a.update_time FROM articles a LEFT JOIN article_categories ac ON a.category_id = ac.id
AND a.title LIKE CONCAT('%', #{dto.title}, '%')
AND a.category_id = #{dto.categoryId}
AND a.status = #{dto.status}
ORDER BY a.is_top DESC, a.create_time DESC
